INSERT INTO testimonials (id, author_name, author_location, rating, content, avatar_url, tour_taken, is_published)
VALUES
('e0014001-0000-4000-8000-000000000001', 'Rajesh Krishnamurthy', 'Chennai, Tamil Nadu', 5, 'We booked the Tirupati Balaji 3D/2N package and it was absolutely seamless. The VIP darshan was arranged perfectly — no waiting in queues for hours. The driver was courteous and on time. Highly recommend Divine Travel for pilgrimage tours!', 'https://images.pexels.com/photos/220453/pexels-photo-220453.jpeg?auto=compress&cs=tinysrgb&w=100', 'Tirupati Balaji Darshan', true),
('e0014002-0000-4000-8000-000000000002', 'Meenakshi Sundaram', 'Coimbatore, Tamil Nadu', 5, 'The Char Dham Yatra package was life-changing. Everything was organized to perfection — from the mountain lodges to the medical support at high altitudes. The guide was knowledgeable and patient. The memory of Kedarnath will stay with us forever.', 'https://images.pexels.com/photos/774909/pexels-photo-774909.jpeg?auto=compress&cs=tinysrgb&w=100', 'Char Dham Yatra 2025', true),
('e0014003-0000-4000-8000-000000000003', 'Anand Balachandran', 'Madurai, Tamil Nadu', 5, 'Kerala backwaters trip exceeded all expectations. The houseboat was clean, the food was delicious, and the backwaters at sunset were magical. Divine Travel team was responsive throughout. Will definitely book again!', 'https://images.pexels.com/photos/614810/pexels-photo-614810.jpeg?auto=compress&cs=tinysrgb&w=100', 'Kerala Backwaters & Hills', true),
('e0014004-0000-4000-8000-000000000004', 'Priyanka Venkatesh', 'Bengaluru, Karnataka', 5, 'Booked the Bali package for our anniversary and it was perfect. The villa was gorgeous, the driver was always on time, and the sunset at Tanah Lot was breathtaking. Divine Travel made our anniversary truly special.', 'https://images.pexels.com/photos/1130626/pexels-photo-1130626.jpeg?auto=compress&cs=tinysrgb&w=100', 'Bali Magical Island', true),
('e0014005-0000-4000-8000-000000000005', 'Suresh Iyer', 'Mumbai, Maharashtra', 5, 'The Varanasi & Prayagraj package was organized brilliantly. The boat ride during Ganga Aarti brought tears to my eyes. The hotel was excellent and the guide explained every ritual in detail. A truly transformative spiritual journey.', 'https://images.pexels.com/photos/1040880/pexels-photo-1040880.jpeg?auto=compress&cs=tinysrgb&w=100', 'Varanasi & Prayagraj Pilgrimage', true),
('e0014006-0000-4000-8000-000000000006', 'Deepa Nambiar', 'Kochi, Kerala', 5, 'Our Maldives honeymoon arranged by Divine Travel was out of this world! The overwater villa was stunning. Every detail — from the airport welcome to the candlelit dinner on the beach — was perfect. Worth every rupee!', 'https://images.pexels.com/photos/1036623/pexels-photo-1036623.jpeg?auto=compress&cs=tinysrgb&w=100', 'Maldives Honeymoon Bliss', true),
('e0014007-0000-4000-8000-000000000007', 'Karthik Raman', 'Hyderabad, Telangana', 5, 'Leh Ladakh trip with Divine Travel was incredible. The guides handled altitude sickness concerns expertly, the Inner Line Permits were pre-arranged, and Pangong Lake at sunrise was a moment I will never forget.', 'https://images.pexels.com/photos/1043474/pexels-photo-1043474.jpeg?auto=compress&cs=tinysrgb&w=100', 'Leh Ladakh Adventure', true),
('e0014008-0000-4000-8000-000000000008', 'Kavitha Narayanan', 'Trichy, Tamil Nadu', 5, 'The Navagraha Temples circuit was exactly what we needed. The astrologer-guide explained the significance of each temple and arranged the special poojas. Our family had a deeply peaceful experience. Thank you Divine Travel!', 'https://images.pexels.com/photos/712513/pexels-photo-712513.jpeg?auto=compress&cs=tinysrgb&w=100', 'Navagraha Temples Circuit', true),
('e0014009-0000-4000-8000-000000000009', 'Mohan Das', 'Thiruvananthapuram, Kerala', 4, 'Good experience overall with the Rajasthan Royal Circuit. Hotels were well chosen, guide was knowledgeable. The only minor issue was a slight delay at the Udaipur heritage hotel check-in. But Divine Travel sorted it quickly. Would book again.', 'https://images.pexels.com/photos/91227/pexels-photo-91227.jpeg?auto=compress&cs=tinysrgb&w=100', 'Rajasthan Royal Circuit', true),
('e0014010-0000-4000-8000-000000000010', 'Sangeetha Pillai', 'Chennai, Tamil Nadu', 5, 'Singapore & Malaysia tour was fantastic value! Divine Travel covered everything — Universal Studios booking, Genting Highlands hotel, Petronas Tower visit. Our kids loved every minute. The local guide in KL was outstanding.', 'https://images.pexels.com/photos/1065084/pexels-photo-1065084.jpeg?auto=compress&cs=tinysrgb&w=100', 'Singapore & Malaysia Tour', true),
('e0014011-0000-4000-8000-000000000011', 'Aravind Subramanian', 'Salem, Tamil Nadu', 5, 'Pancha Bhuta Stalas circuit in 4 days was perfectly planned. I never realized visiting all five elemental Shiva temples in one trip was possible! The guide''s knowledge of the temples'' astrological and mythological significance was exceptional.', 'https://images.pexels.com/photos/1681010/pexels-photo-1681010.jpeg?auto=compress&cs=tinysrgb&w=100', 'Pancha Bhuta Stalas Circuit', true),
('e0014012-0000-4000-8000-000000000012', 'Shanthi Krishnaswamy', 'Pondicherry', 5, 'Rameswaram & Kanyakumari tour was spiritually fulfilling. The sunrise at Kanyakumari was surreal. Divine Travel arranged all the temple darshans smoothly. Accommodation was comfortable. Will recommend to all my friends.', 'https://images.pexels.com/photos/415829/pexels-photo-415829.jpeg?auto=compress&cs=tinysrgb&w=100', 'Rameswaram & Kanyakumari Tour', true)
